import _pickle as cPickle
import base64

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        token = cPickle.loads(decoded)
    except (base64.binascii.Error, cPickle.UnpicklingError, ValueError, TypeError):
        return None
    if isinstance(token, dict) and token.get('valid', False):
        return token.get('data')
    return None

import json
import base64

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        decoded_str = decoded.decode('utf-8')
        token = json.loads(decoded_str)
    except (base64.binascii.Error, json.JSONDecodeError, ValueError, TypeError, UnicodeDecodeError):
        return None
    if isinstance(token, dict) and token.get('valid', False):
        return token.get('data')
    return None

from flask import request, jsonify
import yaml

@app.route('/yaml')
def yaml_load():
    yaml_data = request.args.get('data')
    if not yaml_data:
        return jsonify(error="Missing YAML data"), 400
    try:
        data = yaml.safe_load(yaml_data)
